import React, { useCallback, useMemo, useState } from 'react';
import { Button, NumberInput } from '@linm-soft-org/linm-web-common-components';
import styles from './FpcPlanVoucherPage.module.css';

const TEST_ID = 'fpc-plan-voucher';

/* ── Format helpers ──────────────────────── */
const fVnd = (v: number): string =>
  new Intl.NumberFormat('vi-VN', { style: 'currency', currency: 'VND', maximumFractionDigits: 0 }).format(v);

const fCompact = (v: number): string => {
  const abs = Math.abs(v);
  if (abs >= 1_000_000_000) return `${(abs / 1_000_000_000).toFixed(1)} tỷ`;
  if (abs >= 1_000_000) return `${(abs / 1_000_000).toFixed(0)} triệu`;
  if (abs >= 1_000) return `${(abs / 1_000).toFixed(0)} nghìn`;
  return `${abs.toLocaleString('vi-VN')}`;
};

const todayStr = () => new Date().toISOString().slice(0, 10);

/* ── Types ────────────────────────────────── */
type PlanTab = 'revenue' | 'expense';
type GroupMode = 'item' | 'branch' | 'customer';

interface PlanLine {
  id: string;
  entityCode: string;
  entityName: string;
  entityGroup: string;
  plannedAmount: number;
  actualAmount: number;
}

interface GroupTotal {
  group: string;
  items: PlanLine[];
  totalPlanned: number;
  totalActual: number;
}

