/* ── Status logic ─────────────────────────── */
interface StatusInfo { label: string; color: string; bg: string; }

function getPlanStatus(planned: number, actual: number): StatusInfo {
  if (planned === 0 && actual === 0) return { label: 'Chưa có', color: '#999', bg: '#f1f5f9' };
  if (planned === 0) return { label: 'Chưa lập KH', color: '#92400e', bg: '#fef3c7' };
  const pct = ((actual - planned) / planned) * 100;
  if (Math.abs(pct) <= 10) return { label: 'Đạt', color: '#065f46', bg: '#d1fae5' };
  if (pct < -10) return { label: 'Thấp hơn', color: '#92400e', bg: '#fef3c7' };
  return { label: 'Cao hơn', color: '#991b1b', bg: '#fee2e2' };
}

/* ── Create lines ─────────────────────────── */
function getSourceForMode(tab: PlanTab, groupMode: GroupMode): { code: string; name: string; group: string; actual: number }[] {
  if (groupMode === 'branch') {
    return BRANCHES.map(b => ({ ...b, actual: 0 }));
  }
  if (groupMode === 'customer') {
    return CUSTOMERS.map(c => ({ ...c, actual: 0 }));
  }
  // item mode
  return tab === 'revenue' ? REVENUE_ITEMS : EXPENSE_ITEMS;
}

const createLines = (tab: PlanTab, groupMode: GroupMode, count = 6): PlanLine[] =>
  getSourceForMode(tab, groupMode).slice(0, count).map((s, i) => ({
    id: `line-${tab}-${groupMode}-${i}`,
    entityCode: s.code,
    entityName: s.name,
    entityGroup: s.group,
    plannedAmount: 0,
    actualAmount: s.actual,
  }));

/* ── Sample data ──────────────────────────── */
const SAMPLE_REVENUE: Record<string, number> = {
  DT001: 800_000_000, DT002: 300_000_000, DT003: 170_000_000,
  DT004: 40_000_000, DT005: 28_000_000, DT006: 110_000_000,
  DT007: 60_000_000, DT008: 20_000_000,
};
const SAMPLE_EXPENSE: Record<string, number> = {
  CP001: 160_000_000, CP002: 280_000_000, CP003: 20_000_000, CP004: 10_000_000,
  CP005: 85_000_000, CP006: 280_000_000, CP007: 30_000_000, CP008: 15_000_000,
  CP009: 60_000_000, CP010: 50_000_000, CP011: 4_000_000, CP012: 6_000_000,
};
const SAMPLE_BRANCH: Record<string, number> = {
  HQ: 500_000_000, FM01: 350_000_000, FM02: 280_000_000, FM03: 200_000_000,
  FM04: 180_000_000, FM05: 150_000_000, KHO01: 80_000_000, KHO02: 60_000_000,
};
const SAMPLE_CUSTOMER: Record<string, number> = {
  KH001: 300_000_000, KH002: 250_000_000, KH003: 150_000_000, KH004: 180_000_000,
  KH005: 55_000_000, KH006: 35_000_000, KH007: 80_000_000, KH008: 25_000_000,
  KH009: 22_000_000, KH010: 18_000_000,
};

function getSampleFor(tab: PlanTab, groupMode: GroupMode): Record<string, number> {
  if (groupMode === 'branch') return SAMPLE_BRANCH;
  if (groupMode === 'customer') return SAMPLE_CUSTOMER;
  return tab === 'revenue' ? SAMPLE_REVENUE : SAMPLE_EXPENSE;
}

/* ── Component ────────────────────────────── */
const FpcPlanVoucherPage: React.FC = () => {
  const [activeTab, setActiveTab] = useState<PlanTab>('revenue');
  const [groupMode, setGroupMode] = useState<GroupMode>('item');
  const [lines, setLines] = useState<PlanLine[]>(() => createLines('revenue', 'item'));
  const [editMode, setEditMode] = useState(false);

  /* ── Header state ──────────────────────── */
  const [voucherCode, setVoucherCode] = useState('KH-202607-001');
  const [voucherDate, setVoucherDate] = useState(todayStr());
  const [planYear, setPlanYear] = useState(new Date().getFullYear());
  const [planMonth, setPlanMonth] = useState(new Date().getMonth() + 1);
  const [createdBy, setCreatedBy] = useState('Nguyễn Văn A');
  const [description, setDescription] = useState(`Kế hoạch tài chính tháng ${new Date().getMonth() + 1}/${new Date().getFullYear()}`);
  const [saving, setSaving] = useState(false);
  const [saved, setSaved] = useState(false);

  /* ── Switch tab or group mode ──────────── */
  const switchTab = useCallback((tab: PlanTab) => {
    setActiveTab(tab);
    setLines(createLines(tab, groupMode));
    setEditMode(false);
  }, [groupMode]);

  const switchGroup = useCallback((mode: GroupMode) => {
    setGroupMode(mode);
    setLines(createLines(activeTab, mode));
    setEditMode(false);
  }, [activeTab]);

  /* ── Line handler ───────────────────────── */
  const handleLineChange = useCallback((id: string, field: keyof PlanLine, value: number) => {
    setLines(prev => prev.map(line =>
      line.id === id ? { ...line, [field]: value } : line
    ));
  }, []);

  const handleAddLine = useCallback(() => {
    const source = getSourceForMode(activeTab, groupMode);
    const usedCodes = lines.map(l => l.entityCode);
    const unused = source.find(s => !usedCodes.includes(s.code));
    if (!unused) return;
    setLines(prev => [...prev, {
      id: `line-${Date.now()}`,
      entityCode: unused.code,
      entityName: unused.name,
      entityGroup: unused.group,
      plannedAmount: 0,
      actualAmount: unused.actual,
    }]);
  }, [activeTab, groupMode, lines]);

  const handleRemoveLine = useCallback((id: string) => {
    setLines(prev => prev.filter(line => line.id !== id));
  }, []);

  /* ── Fill sample ───────────────────────── */
  const handleFillSample = useCallback(() => {
    const sample = getSampleFor(activeTab, groupMode);
    setLines(prev => prev.map(line => ({
      ...line,
      plannedAmount: sample[line.entityCode] || 0,
    })));
  }, [activeTab, groupMode]);

  /* ── Save / Print ───────────────────────── */
  const handleSave = useCallback(async () => {
    setSaving(true);
    await new Promise(r => setTimeout(r, 600));
    setSaving(false);
    setSaved(true);
    setEditMode(false);
    setTimeout(() => setSaved(false), 3000);
  }, []);

  const handlePrint = useCallback(() => {
    const el = document.getElementById('plan-voucher-content');
    if (!el) return;
    const win = window.open('', '_blank');
    if (!win) return;
    win.document.write([
      '<html><head><title>Phiếu kế hoạch</title><style>',
      'body{font-family:Arial,sans-serif;padding:20px;color:#1e293b}',
      'table{width:100%;border-collapse:collapse;margin:16px 0}',
      'th,td{padding:8px 12px;border:1px solid #e2e8f0;text-align:left;font-size:12px}',
      'th{background:#f8fafc;font-weight:600}',
      'h1{font-size:22px;color:#8b5cf6}',
      '.right{text-align:right}.money{font-family:monospace;text-align:right}',
      '.demo-badge{display:inline-block;padding:2px 8px;border-radius:4px;font-size:11px;background:#fef3c7;color:#92400e}',
      '.positive{color:#059669}.negative{color:#ef4444}',
      '</style></head><body>',
      '<h1>Phiếu kế hoạch <span class="demo-badge">DỮ LIỆU MÔ PHỎNG</span></h1>',
      '<p>Ngày in: ' + new Date().toLocaleString('vi-VN') + '</p>',
      el.innerHTML,
      '</body></html>',
    ].join('\n'));
    win.document.close();
    win.print();
  }, []);

  /* ── Computed ───────────────────────────── */
  const groupedLines = useMemo((): GroupTotal[] => {
    const map = new Map<string, PlanLine[]>();
    lines.forEach(line => {
      const g = line.entityGroup || 'Khác';
      if (!map.has(g)) map.set(g, []);
      map.get(g)!.push(line);
    });
    return Array.from(map.entries()).map(([group, items]) => ({
      group,
      items,
      totalPlanned: items.reduce((s, i) => s + i.plannedAmount, 0),
      totalActual: items.reduce((s, i) => s + i.actualAmount, 0),
    }));
  }, [lines]);

  const totalPlanned = lines.reduce((s, l) => s + l.plannedAmount, 0);
  const totalActual = lines.reduce((s, l) => s + l.actualAmount, 0);
  const totalVariance = totalActual - totalPlanned;
  const activeCount = lines.filter(l => l.plannedAmount > 0).length;

  const currentSource = getSourceForMode(activeTab, groupMode);
  const maxLines = currentSource.length;

  const now = new Date();
  const dateLabel = `Tháng ${planMonth}/${planYear}`;

  /* ── Render ────────────────────────────── */
  return (
    <div className={styles.page} data-form-page data-testid={`${TEST_ID}-page`}>
      {/* ── Page header ── */}
      <div className={styles.pageHeader}>
        <div className={styles.titleBlock}>
          <h1 className={styles.title}>
            <i className="fas fa-clipboard-list" />
            Phiếu kế hoạch
          </h1>
          <p className={styles.subtitle}>
            Lập kế hoạch thu / chi — theo khoản mục, chi nhánh hoặc khách hàng
            <span className={styles.phaseTag} style={{ marginLeft: 8, background: '#fef3c7', color: '#92400e' }}>DỮ LIỆU MÔ PHỎNG</span>
          </p>
        </div>
        <div className={styles.toolbar}>
          {editMode ? (
            <>
              <Button variant="primary" onClick={handleSave} disabled={saving}>
                <i className="fas fa-save" style={{ marginRight: 6 }} />
                {saving ? 'Đang lưu...' : 'Lưu'}
              </Button>
              <Button onClick={() => { setEditMode(false); }}>Hủy</Button>
            </>
          ) : (
            <>
              <Button variant="primary" onClick={() => setEditMode(true)}>
                <i className="fas fa-edit" style={{ marginRight: 6 }} />
                Nhập số liệu
              </Button>
              <Button onClick={handlePrint}>
                <i className="fas fa-print" style={{ marginRight: 6 }} />
                In
              </Button>
              <Button onClick={() => { setLines(createLines(activeTab, groupMode)); setSaved(false); }}>
                <i className="fas fa-redo" style={{ marginRight: 6 }} />
                Làm mới
              </Button>
            </>
          )}
          {saved && (
            <span style={{ display: 'inline-flex', alignItems: 'center', gap: 6, padding: '6px 14px', background: '#d1fae5', color: '#065f46', borderRadius: 8, fontSize: 13, fontWeight: 600 }}>
              <i className="fas fa-check-circle" />
              Đã lưu dữ liệu mô phỏng
            </span>
          )}
        </div>
      </div>

      <div className={styles.formShell} id="plan-voucher-content">
        {/* ── Header info ── */}
        <div className={styles.sectionCard}>
          <div className={styles.sectionHeader}>
            <h2 className={styles.sectionTitle}>
              <i className="fas fa-info-circle" style={{ color: '#8b5cf6' }} />
              Thông tin phiếu kế hoạch
            </h2>
            <span className={styles.sectionBadge}>{dateLabel}</span>
          </div>
          <div className={styles.headerGrid}>
            <div className={styles.fieldGroup}>
              <label className={styles.fieldLabel}>Số phiếu</label>
              <input className={styles.fieldInput} value={voucherCode} onChange={e => setVoucherCode(e.target.value)} />
            </div>
            <div className={styles.fieldGroup}>
              <label className={styles.fieldLabel}>Ngày lập</label>
              <input type="date" className={styles.fieldInput} value={voucherDate} onChange={e => setVoucherDate(e.target.value)} />
            </div>
            <div className={styles.fieldGroup}>
              <label className={styles.fieldLabel}>Kỳ kế hoạch</label>
              <div style={{ display: 'flex', gap: 8 }}>
                <select className={styles.fieldSelect} value={planMonth} onChange={e => setPlanMonth(parseInt(e.target.value))} style={{ flex: 1 }}>
                  {Array.from({ length: 12 }, (_, i) => (
                    <option key={i + 1} value={i + 1}>Tháng {i + 1}</option>
                  ))}
                </select>
                <input type="number" className={styles.fieldInput} value={planYear} onChange={e => setPlanYear(parseInt(e.target.value) || now.getFullYear())} style={{ width: 90 }} />
              </div>
            </div>
            <div className={styles.fieldGroup}>
              <label className={styles.fieldLabel}>Người lập</label>
              <input className={styles.fieldInput} value={createdBy} onChange={e => setCreatedBy(e.target.value)} />
            </div>
            <div className={styles.fieldGroup} style={{ gridColumn: '1 / -1' }}>
              <label className={styles.fieldLabel}>Mục tiêu</label>
              <input className={styles.fieldInput} value={description} onChange={e => setDescription(e.target.value)} placeholder="Nhập mục tiêu kế hoạch" />
            </div>
          </div>
        </div>

        {/* ── Summary bar ── */}
        <div className={styles.statsRow}>
          <div className={styles.statCard}>
            <span className={styles.statLabel}>Kỳ kế hoạch</span>
            <span className={styles.statValue} style={{ fontSize: 18 }}>{dateLabel}</span>
          </div>
          <div className={styles.statCard}>
            <span className={styles.statLabel}>Tổng kế hoạch</span>
            <span className={styles.statValue}>{fCompact(totalPlanned)}</span>
          </div>
          <div className={styles.statCard}>
            <span className={styles.statLabel}>Thực tế</span>
            <span className={`${styles.statValue} ${totalActual >= 0 ? styles.positive : styles.negative}`}>{fCompact(totalActual)}</span>
          </div>
          <div className={styles.statCard}>
            <span className={styles.statLabel}>Chênh lệch</span>
            <span className={`${styles.statValue} ${totalVariance >= 0 ? styles.positive : styles.negative}`}>
              {totalVariance >= 0 ? '+' : ''}{fCompact(totalVariance)}
            </span>
          </div>
        </div>

        {/* ── Tabs + Group toggle ── */}
        <div className={styles.sectionCard} style={{ padding: 0, overflow: 'hidden' }}>
          {/* Tab bar */}
          <div className={styles.tabBar}>
            <button
              className={`${styles.tabBtn} ${activeTab === 'revenue' ? styles.tabActiveRevenue : ''}`}
              onClick={() => switchTab('revenue')}
            >
              <i className="fas fa-arrow-up" style={{ marginRight: 6 }} />
              Kế hoạch thu
            </button>
            <button
              className={`${styles.tabBtn} ${activeTab === 'expense' ? styles.tabActiveExpense : ''}`}
              onClick={() => switchTab('expense')}
            >
              <i className="fas fa-arrow-down" style={{ marginRight: 6 }} />
              Kế hoạch chi
            </button>
          </div>

          {/* Body */}
          <div style={{ padding: 20 }}>
            {/* Group mode toggle */}
            <div className={styles.sectionHeader} style={{ borderBottom: '1px solid #f1f5f9', paddingBottom: 12, marginBottom: 16 }}>
              <h2 className={styles.sectionTitle}>
                {activeTab === 'revenue' ? (
                  <><i className="fas fa-arrow-up" style={{ color: '#059669' }} />Kế hoạch thu</>
                ) : (
                  <><i className="fas fa-arrow-down" style={{ color: '#ef4444' }} />Kế hoạch chi</>
                )}
              </h2>
              <div style={{ display: 'flex', gap: 6, flexWrap: 'wrap' }}>
                {([['item', 'Theo khoản mục'], ['branch', 'Theo chi nhánh'], ['customer', 'Theo khách hàng']] as [GroupMode, string][]).map(([mode, label]) => (
                  <button
                    key={mode}
                    onClick={() => switchGroup(mode)}
                    style={{
                      padding: '6px 16px', borderRadius: 8, border: '1px solid #e2e8f0', fontSize: 13, fontWeight: 600, cursor: 'pointer', transition: 'all 0.2s',
                      background: groupMode === mode ? '#8b5cf6' : '#fff',
                      color: groupMode === mode ? '#fff' : '#64748b',
                    }}
                  >{label}</button>
                ))}
              </div>
            </div>

            {/* Fill sample prompt (edit mode only) */}
            {editMode && (
              <div style={{ display: 'flex', alignItems: 'center', gap: 12, padding: '12px 16px', background: '#faf5ff', borderRadius: 10, border: '1px dashed #c4b5fd', marginBottom: 16 }}>
                <i className="fas fa-lightbulb" style={{ color: '#8b5cf6', fontSize: 16 }} />
                <span style={{ flex: 1, fontSize: 13, color: '#6b21a8' }}>
                  Nhập số liệu thủ công hoặc nhấn <strong>"Điền dữ liệu mẫu"</strong> để xem trước
                </span>
                <Button onClick={handleFillSample}>
                  <i className="fas fa-magic" style={{ marginRight: 6 }} />
                  Điền dữ liệu mẫu
                </Button>
              </div>
            )}

            {/* Lines table */}
            <div className={styles.tableWrapper}>
              <table className={styles.table}>
                <thead>
                  <tr>
                    <th style={{ width: 36 }}>STT</th>
                    <th style={{ width: 100 }}>Mã</th>
                    <th>
                      {groupMode === 'item' && (activeTab === 'revenue' ? 'Khoản thu' : 'Khoản chi')}
                      {groupMode === 'branch' && 'Chi nhánh'}
                      {groupMode === 'customer' && 'Khách hàng'}
                    </th>
                    {editMode ? (
                      <th className={styles.colRight} style={{ width: 150 }}>Kế hoạch</th>
                    ) : (
                      <>
                        <th className={styles.colRight} style={{ width: 140 }}>Kế hoạch</th>
                        <th className={styles.colRight} style={{ width: 140 }}>Thực tế</th>
                        <th className={styles.colRight} style={{ width: 100 }}>Chênh lệch</th>
                        <th className={styles.colCenter} style={{ width: 110 }}>Trạng thái</th>
                      </>
                    )}
                    {editMode && <th style={{ width: 36 }}></th>}
                  </tr>
                </thead>
                <tbody>
                  {groupedLines.map(g => (
                    <React.Fragment key={g.group}>
                      <tr style={{ background: '#f8fafc' }}>
                        <td colSpan={editMode ? 5 : 7} style={{ padding: '6px 14px', fontSize: 12, fontWeight: 600, color: '#8b5cf6', letterSpacing: 0.3 }}>
                          {g.group} — {editMode ? '' : `KH: ${fCompact(g.totalPlanned)} / TT: ${fCompact(g.totalActual)}`}
                        </td>
                      </tr>
                      {g.items.map((line, idx) => (
                        <tr key={line.id}>
                          <td style={{ textAlign: 'center', color: '#94a3b8', fontWeight: 500 }}>{idx + 1}</td>
                          <td style={{ fontWeight: 500, color: '#1e293b', fontSize: 12 }}>{line.entityCode}</td>
                          <td style={{ color: '#475569' }}>{line.entityName}</td>
                          {editMode ? (
                            <td>
                              <NumberInput
                                className={styles.lineInput}
                                value={line.plannedAmount}
                                onChange={v => handleLineChange(line.id, 'plannedAmount', v)}
                                placeholder="0"
                              />
                            </td>
                          ) : (
                            <>
                              <td className={styles.colAmount}>{fVnd(line.plannedAmount)}</td>
                              <td className={styles.colAmount}>{fVnd(line.actualAmount)}</td>
                              <td className={styles.colAmount}>
                                {(() => {
                                  const diff = line.actualAmount - line.plannedAmount;
                                  return (
                                    <span style={{ fontWeight: 600, color: diff >= 0 ? '#059669' : '#ef4444' }}>
                                      {diff >= 0 ? '+' : ''}{fVnd(diff)}
                                    </span>
                                  );
                                })()}
                              </td>
                              <td className={styles.colCenter}>
                                {(() => {
                                  const st = getPlanStatus(line.plannedAmount, line.actualAmount);
                                  return (
                                    <span style={{ display: 'inline-flex', alignItems: 'center', gap: 4, padding: '2px 10px', borderRadius: 12, fontSize: 11, fontWeight: 600, background: st.bg, color: st.color }}>
                                      {st.label}
                                    </span>
                                  );
                                })()}
                              </td>
                            </>
                          )}
                          {editMode && (
                            <td style={{ textAlign: 'center' }}>
                              <button onClick={() => handleRemoveLine(line.id)} style={{ border: 'none', background: 'none', color: '#ef4444', cursor: 'pointer', fontSize: 14, padding: 4 }} title="Xóa dòng">
                                <i className="fas fa-times" />
                              </button>
                            </td>
                          )}
                        </tr>
                      ))}
                    </React.Fragment>
                  ))}
                </tbody>
                {!editMode && lines.length > 0 && (
                  <tfoot>
                    <tr style={{ background: '#f8fafc', fontWeight: 700 }}>
                      <td colSpan={3} style={{ padding: '10px 14px', color: '#1e293b' }}>Tổng cộng</td>
                      <td className={styles.colAmount} style={{ fontFamily: 'monospace' }}>{fVnd(totalPlanned)}</td>
                      <td className={styles.colAmount} style={{ fontFamily: 'monospace' }}>{fVnd(totalActual)}</td>
                      <td className={styles.colAmount} style={{ fontFamily: 'monospace', color: totalVariance >= 0 ? '#059669' : '#ef4444' }}>
                        {totalVariance >= 0 ? '+' : ''}{fVnd(totalVariance)}
                      </td>
                      <td></td>
                    </tr>
                  </tfoot>
                )}
              </table>
            </div>

            {editMode && (
              <div style={{ marginTop: 12 }}>
                <Button onClick={handleAddLine} disabled={lines.length >= maxLines}>
                  <i className="fas fa-plus" style={{ marginRight: 6 }} />
                  Thêm dòng
                </Button>
              </div>
            )}

            {!editMode && activeCount === 0 && (
              <div style={{ padding: '32px 0', textAlign: 'center', color: '#94a3b8' }}>
                <i className="fas fa-inbox" style={{ fontSize: 32, display: 'block', marginBottom: 12 }} />
                Chưa có dữ liệu cho {activeTab === 'revenue' ? 'kế hoạch thu' : 'kế hoạch chi'}. Nhấn <strong>"Nhập số liệu"</strong> để nhập.
              </div>
            )}
          </div>
        </div>

        {/* ── Footer totals ── */}
        {!editMode && activeCount > 0 && (
          <div className={styles.footerRow}>
            <div className={styles.footerItem}>
              <span className={styles.footerLabel}>Loại kế hoạch</span>
              <span className={styles.footerValue} style={{ fontSize: 16, color: activeTab === 'revenue' ? '#059669' : '#ef4444' }}>
                {activeTab === 'revenue' ? 'Kế hoạch thu' : 'Kế hoạch chi'}
              </span>
            </div>
            <div className={styles.footerItem}>
              <span className={styles.footerLabel}>Tổng kế hoạch</span>
              <span className={styles.footerValue}>{fCompact(totalPlanned)}</span>
            </div>
            <div className={styles.footerItem}>
              <span className={styles.footerLabel}>Thực tế</span>
              <span className={`${styles.footerValue} ${totalActual >= 0 ? styles.positive : ''}`}>{fCompact(totalActual)}</span>
            </div>
            <div className={styles.footerItem}>
              <span className={styles.footerLabel}>Chênh lệch</span>
              <span className={`${styles.footerValue} ${totalVariance >= 0 ? styles.positive : styles.negative}`}>
                {totalVariance >= 0 ? '+' : ''}{fCompact(totalVariance)}
              </span>
            </div>
            <div className={styles.footerItem}>
              <span className={styles.footerLabel}>Số dòng</span>
              <span className={styles.footerValue}>{activeCount}</span>
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

export default FpcPlanVoucherPage;
